const hoje = new Date();
const d1 = new Date(hoje);
d1.setDate(d1.getDate() - 1);

const pad = n => String(n).padStart(2, '0');
const ano = d1.getFullYear();
const mes = pad(d1.getMonth() + 1);
const dia = pad(d1.getDate());
const dataInicio = `${ano}-${mes}-${dia}`;

return [{
  json: {
    dataInicio,
    dataFim: dataInicio,
    dataFormatadaBR: `${dia}/${mes}/${ano}`,
    dataHoraExecucao: new Date().toLocaleTimeString('pt-BR'),
    inicioExecucao: Date.now(),
    ano: String(ano),
    mes
  }
}];

// ============================================================
// CONFRONTO ADQUIRENTE (maquininha) vs ERP
//
// Estrutura esperada da resposta da adquirente:
//   { content: { transactions: [...] }, cursor: { hasNextKey: bool, nextKey: str } }
//
// Chave 1 (principal): numero de autorizacao
//   Adquirente: authorizationCode (int, pode ser 0)
//               -> fallback: strAuthorizationCode (string)
//   ERP:        Numero_Autorizacao
//
// Chave 2 (fallback): NSU
//   Adquirente: nsu (int) | ERP: NSU
//
// Valor da venda (amount) e o valor bruto em R$ (nao centavos).
// MDR (discountAmount) e a taxa retida pela adquirente.
// Regra: valor_erp deve bater com valor_bruto (venda registrada).
// Tolerancia de R$ 0,01; diferencas de centavo no MDR sao OK.
// ============================================================

const pages = $('Adquirente - Buscar Vendas').all();
const todasTransacoes = [];
pages.forEach(page => {
  const transactions = page.json?.content?.transactions || [];
  todasTransacoes.push(...transactions);
});

const erpList = $input.all().map(i => i.json);

const resultado = {
  ok: [], okArredondamento: [], divergentes: [],
  naoEncontradosAdq: [], naoEncontradosERP: [], cancelados: []
};

// Mapa de bandeiras (codigos genericos de exemplo)
const BANDEIRAS = {
  1: 'Bandeira A', 2: 'Bandeira B', 3: 'Bandeira C',
  4: 'Bandeira D', 5: 'Bandeira E', 6: 'Bandeira F'
};

function normAdq(r) {
  let authCode = '';
  if (r.authorizationCode !== undefined && r.authorizationCode !== 0) {
    authCode = String(r.authorizationCode).trim();
  } else if (r.strAuthorizationCode) {
    authCode = String(r.strAuthorizationCode).trim();
  }
  return {
    nsu:                String(r.nsu || '').trim(),
    numero_autorizacao: authCode,
    bandeira:           BANDEIRAS[r.brandCode] || `Cod ${r.brandCode || '?'}`,
    modalidade:         r.modality?.type    || '',
    produto:            r.modality?.product || '',
    parcelas:           r.installmentQuantity || 1,
    valor_bruto:        Number(r.amount)         || 0,
    valor_liquido:      Number(r.netAmount)      || 0,
    valor_mdr:          Number(r.discountAmount) || 0,
    taxa_mdr_pct:       Number(r.mdrFee)         || 0,
    data_transacao:     r.saleDate || r.movementDate || '',
    status:             (r.status || '').toUpperCase(),
    numero_terminal:    r.device || r.tid || '',
    tipo_captura:       r.captureType || ''
  };
}

const adqList = todasTransacoes.map(normAdq);

const adqAtivas = adqList.filter(r => {
  if (['CANCELADA','CANCELLED','CANCELADO','CANCELED'].includes(r.status)) {
    resultado.cancelados.push(r);
    return false;
  }
  return true;
});

const erpMapAuth = {};
const erpMapNSU  = {};
erpList.forEach(i => {
  const auth = String(i.Numero_Autorizacao || '').trim();
  const nsu  = String(i.NSU || '').trim();
  if (auth) erpMapAuth[auth] = i;
  if (nsu)  erpMapNSU[nsu]   = i;
});

const authConfrontados = new Set();

adqAtivas.forEach(adq => {
  let erp = erpMapAuth[adq.numero_autorizacao];
  if (!erp && adq.nsu) erp = erpMapNSU[adq.nsu];

  if (!erp) {
    resultado.naoEncontradosAdq.push({
      numero_autorizacao: adq.numero_autorizacao,
      nsu:                adq.nsu,
      bandeira:           adq.bandeira,
      modalidade:         adq.modalidade,
      produto:            adq.produto,
      parcelas:           adq.parcelas,
      tipo_captura:       adq.tipo_captura,
      valor_adq:          adq.valor_bruto,
      valor_mdr:          adq.valor_mdr,
      data:               adq.data_transacao,
      numero_terminal:    adq.numero_terminal,
      status_conciliacao: 'NAO ENCONTRADO NO ERP'
    });
    return;
  }

  authConfrontados.add(String(erp.Numero_Autorizacao || '').trim());

  const valorAdq       = adq.valor_bruto;
  const valorERP       = Number(erp.Valor_Pagamento);
  const valorMDR       = adq.valor_mdr;
  const diff           = Math.abs(valorAdq - valorERP);
  const calculoLiquido = valorAdq - valorMDR;
  const arredondamento = Math.abs(calculoLiquido - valorERP);

  const base = {
    numero_autorizacao: adq.numero_autorizacao,
    nsu:                adq.nsu,
    numero_documento:   erp.Numero_Documento,
    tipo_documento:     erp.Tipo_Documento,
    numero_terminal:    adq.numero_terminal,
    tipo_captura:       adq.tipo_captura,
    bandeira:           adq.bandeira,
    modalidade:         adq.modalidade,
    produto:            adq.produto,
    parcelas:           adq.parcelas,
    usuario:            erp.Usuario,
    forma_pagamento:    erp.Forma_Pagamento,
    valor_adq:          valorAdq,
    valor_erp:          valorERP,
    diferenca:          parseFloat((valorAdq - valorERP).toFixed(2)),
    calculo_liquido:    parseFloat(calculoLiquido.toFixed(4)),
    valor_mdr:          valorMDR,
    taxa_mdr_pct:       adq.taxa_mdr_pct,
    data:               adq.data_transacao
  };

  if (diff < 0.01) {
    resultado.ok.push({ ...base, status_conciliacao: 'OK' });
  } else if (arredondamento < 0.01) {
    resultado.okArredondamento.push({ ...base, status_conciliacao: 'OK (ARREDONDAMENTO MDR)' });
  } else {
    resultado.divergentes.push({ ...base, status_conciliacao: 'DIVERGENTE' });
  }
});

erpList.forEach(erp => {
  const auth = String(erp.Numero_Autorizacao || '').trim();
  if (auth && !authConfrontados.has(auth)) {
    resultado.naoEncontradosERP.push({
      numero_autorizacao: erp.Numero_Autorizacao,
      nsu:                erp.NSU,
      numero_documento:   erp.Numero_Documento,
      tipo_documento:     erp.Tipo_Documento,
      forma_pagamento:    erp.Forma_Pagamento,
      usuario:            erp.Usuario,
      valor_erp:          erp.Valor_Pagamento,
      data:               erp.Data_Emissao,
      status_conciliacao: 'NAO ENCONTRADO NA ADQUIRENTE'
    });
  }
});

console.log(`[Confronto] OK=${resultado.ok.length} | Arred=${resultado.okArredondamento.length} | Div=${resultado.divergentes.length} | s/ERP=${resultado.naoEncontradosAdq.length} | s/Adq=${resultado.naoEncontradosERP.length} | Cancel=${resultado.cancelados.length}`);

return [{ json: resultado }];

const XLSX = require('xlsx');

const dados = $input.first().json;
const datas = $('Calcular Datas D-1').first().json;

function linhaDiv(item) {
  return {
    'NSU':              item.nsu || '',
    'No Autorizacao':   item.numero_autorizacao || '',
    'Terminal':         item.numero_terminal || '',
    'Tipo Captura':     item.tipo_captura || '',
    'Bandeira':         item.bandeira || '',
    'Modalidade':       item.modalidade || '',
    'Produto':          item.produto || '',
    'Data':             item.data || '',
    'Valor Adq (R$)':   item.valor_adq || 0,
    'Valor ERP (R$)':   item.valor_erp || 0,
    'Diferenca (R$)':   item.diferenca || 0,
    'MDR (R$)':         item.valor_mdr || 0,
    'MDR (%)':          item.taxa_mdr_pct || 0,
    'Status':           item.status_conciliacao
  };
}

function linhaCompleta(item) {
  return {
    'NSU':              item.nsu || '',
    'No Autorizacao':   item.numero_autorizacao || '',
    'Terminal':         item.numero_terminal || '',
    'Tipo Captura':     item.tipo_captura || '',
    'Bandeira':         item.bandeira || '',
    'Modalidade':       item.modalidade || '',
    'Produto':          item.produto || '',
    'Parcelas':         item.parcelas || '',
    'Data':             item.data || '',
    'Usuario ERP':      item.usuario || '',
    'No Documento':     item.numero_documento || '',
    'Tipo Documento':   item.tipo_documento || '',
    'Forma Pagamento':  item.forma_pagamento || '',
    'Valor Adq (R$)':   item.valor_adq || 0,
    'Valor ERP (R$)':   item.valor_erp || 0,
    'Diferenca (R$)':   item.diferenca || 0,
    'Calculo Liquido':  item.calculo_liquido || 0,
    'MDR (R$)':         item.valor_mdr || 0,
    'MDR (%)':          item.taxa_mdr_pct || 0,
    'Arredondamento MDR': item.status_conciliacao === 'OK (ARREDONDAMENTO MDR)' ? 'Sim' : 'Nao',
    'Status':           item.status_conciliacao
  };
}

const linhasDivergencias = [
  ...dados.divergentes,
  ...dados.naoEncontradosAdq,
  ...dados.naoEncontradosERP
].map(linhaDiv);

const todasLinhas = [
  ...dados.ok,
  ...dados.okArredondamento,
  ...dados.divergentes,
  ...dados.naoEncontradosAdq,
  ...dados.naoEncontradosERP
].map(linhaCompleta);

const wb = XLSX.utils.book_new();

const wsDiv = XLSX.utils.json_to_sheet(
  linhasDivergencias.length > 0
    ? linhasDivergencias
    : [{ 'Resultado': 'Nenhuma divergencia encontrada', 'Data': datas.dataFormatadaBR }]
);
const wsComp = XLSX.utils.json_to_sheet(
  todasLinhas.length > 0
    ? todasLinhas
    : [{ 'Resultado': 'Nenhuma transacao processada', 'Data': datas.dataFormatadaBR }]
);

XLSX.utils.book_append_sheet(wb, wsDiv,  'Divergencias');
XLSX.utils.book_append_sheet(wb, wsComp, 'Confronto Completo');

const buffer      = XLSX.write(wb, { type: 'buffer', bookType: 'xlsx' });
const nomeArquivo = `Conciliacao_Vendas_${datas.dataInicio}.xlsx`;

return [{
  json: {
    nomeArquivo,
    pastaAno:          datas.ano,
    pastaMes:          datas.mes,
    dataInicio:        datas.dataInicio,
    totalLinhas:       todasLinhas.length,
    totalDivergencias: linhasDivergencias.length
  },
  binary: {
    data: {
      data:     buffer.toString('base64'),
      mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      fileName: nomeArquivo
    }
  }
}];

const dados   = $('Confronto NSU + MDR').first().json;
const datas   = $('Calcular Datas D-1').first().json;
const arquivo = $('Gerar Excel').first().json;
const spResp  = $('SharePoint - Upload Arquivo').first().json;

const total = dados.ok.length + dados.okArredondamento.length
            + dados.divergentes.length + dados.naoEncontradosAdq.length
            + dados.naoEncontradosERP.length;

const somar = (arr, campo) => arr.reduce((s, i) => s + (Number(i[campo]) || 0), 0);

const valorBrutoAdq = somar([...dados.ok, ...dados.okArredondamento, ...dados.divergentes, ...dados.naoEncontradosAdq], 'valor_adq');
const valorERP      = somar([...dados.ok, ...dados.okArredondamento, ...dados.divergentes, ...dados.naoEncontradosERP], 'valor_erp');
const diferencaLiq  = valorBrutoAdq - valorERP;

const temDiv = dados.divergentes.length > 0 || dados.naoEncontradosAdq.length > 0 || dados.naoEncontradosERP.length > 0;
const cor    = temDiv ? 'FF8C00' : '00B050';
const titulo = temDiv
  ? `Conciliacao de Vendas - ${datas.dataFormatadaBR} - ATENCAO: ha divergencias`
  : `Conciliacao de Vendas - ${datas.dataFormatadaBR} - Conciliado sem divergencias`;

const linkArquivo = spResp?.webUrl || arquivo.nomeArquivo;
const tempoTotal  = Math.round((Date.now() - datas.inicioExecucao) / 1000);

const card = {
  '@type':    'MessageCard',
  '@context': 'http://schema.org/extensions',
  themeColor: cor,
  summary:    `Conciliacao Vendas ${datas.dataFormatadaBR}`,
  sections: [{
    activityTitle:    titulo,
    activitySubtitle: 'Resultado automatico - Contas a Receber',
    facts: [
      { name: 'Vendas OK:',                value: String(dados.ok.length) },
      { name: 'Arredondamento MDR:',       value: `${dados.okArredondamento.length} (centavos - OK)` },
      { name: 'Divergencias reais:',       value: String(dados.divergentes.length) },
      { name: 'Nao no ERP:',               value: String(dados.naoEncontradosAdq.length) },
      { name: 'Nao na adquirente:',        value: String(dados.naoEncontradosERP.length) },
      { name: 'Canceladas (excluidas):',   value: String(dados.cancelados.length) },
      { name: 'Total confrontado:',        value: String(total) },
      { name: 'Valor bruto adquirente:',   value: `R$ ${valorBrutoAdq.toFixed(2)}` },
      { name: 'Valor ERP:',                value: `R$ ${valorERP.toFixed(2)}` },
      { name: 'Diferenca liquida:',        value: `R$ ${diferencaLiq.toFixed(2)}` },
      { name: 'Arquivo:',                  value: linkArquivo },
      { name: `Execucao ${datas.dataHoraExecucao}`, value: `${tempoTotal}s` }
    ]
  }]
};

return [{ json: { payload: JSON.stringify(card) } }];

